customCSS:
/* Theme Modal */
.modal { background: rgba(0,0,0,0.42) !important; backdrop-filter: blur(12px) saturate(140%) !important; -webkit-backdrop-filter: blur(12px) saturate(140%) !important; }
.modal-content { background: linear-gradient(180deg, rgba(255,255,255,0.20), rgba(255,255,255,0.08)) !important; border: 1px solid rgba(255,255,255,0.42) !important; border-radius: 12px !important; box-shadow: 0 24px 64px rgba(0,0,0,0.38), inset 0 1px 0 rgba(255,255,255,0.42) !important; color: #fff !important; backdrop-filter: blur(18px) saturate(150%) !important; -webkit-backdrop-filter: blur(18px) saturate(150%) !important; }
.modal-title, .settings-title, .modal-content h4 { color: #f6f6ff !important; }
.app-dialog-message, .trigger-description, .community-template .description { color: #fff !important; }
.import-hint, .settings-help, .hotkey-help, .range-labels, .community-template .task-count { color: rgba(255,255,255,0.72) !important; }
.community-template { background: rgba(255,255,255,0.10) !important; border: 1px solid rgba(255,255,255,0.22) !important; }
.modal-btn.primary { background: rgba(65,105,225,0.78) !important; border: 1px solid rgba(255,255,255,0.42) !important; color: #fff !important; }
.modal-btn.secondary { background: rgba(255,255,255,0.12) !important; border: 1px solid rgba(255,255,255,0.28) !important; color: #fff !important; }
.modal-btn:hover { box-shadow: 0 0 0 2px rgba(255,255,255,0.18) !important; }
.modal-content-dialog.app-dialog-tone-danger { border-color: rgba(255,90,120,0.82) !important; }
.modal-content-dialog.app-dialog-tone-danger .modal-title { color: #ffb3c0 !important; }
